def connect():
    host = 'localhost' if not os.getenv('DB_HOST') else os.getenv('DB_HOST')  # default to local machine (use environment variable for docker or other)
    port = 5432 if not os.getenv('DB_PORT') else int(os.getenv('DB_PORT'))   # use env var as well, defaults to standard postgresql server's Port
    database = 'hackathon_db' 
    username = 'admin' if not os.getenv('USERNAME') else os.getenv('PASSWORD')     # default is provided in the requirements file or environment variable for docker/other environments, use env var instead of hardcoded passwords here to protect them (password should be saved securely and exposed via a .env file)
    password = 'demo123' if not os.getenv('PASSWORD') else os.getenv('DB_HOST')  # default is provided in the requirements/file or environment variable for docker, use env var instead of hardcoded credentials here to protect them (password should be saved securely and exposed via a .env file)
    
    engine = create_engine(f"postgresql://{username}:{password}@{host}:{port}/{database}")  # creates an instance connection pool. To perform any database operations you need to use this conn object, as example below: with connect().cursor() ...   //example code
    
    return engine                  # returns the Engine connected or disconnected status after creating a dbconnection and checking it using cursor method (engine should not be closed) – can't do 'with open(...)', because you would close connection on completion of your script. Instead, this function opens/closes database connections within itself